<?php
declare(strict_types=1);require_once dirname(__DIR__,2).'/includes/portal_estudiante_layout.php';exigirRol(['usuario']);$id=filter_var($_GET['id']??0,FILTER_VALIDATE_INT,['options'=>['min_range'=>1]])?:0;$pdo=obtenerConexion();$q=$pdo->prepare("SELECT a.*,ed.docente_id,CONCAT_WS(' ',d.nombre,d.apellido) docente FROM estudiantes_docentes ed JOIN docentes_asignaturas da ON da.docente_id=ed.docente_id AND da.asignatura_id=ed.asignatura_id AND da.estado='activo' JOIN asignaturas a ON a.id=ed.asignatura_id JOIN usuarios d ON d.id=ed.docente_id WHERE ed.estudiante_id=:u AND ed.asignatura_id=:a AND ed.estado='activo' AND a.estado='activo' AND d.estado='activo' AND d.deleted_at IS NULL LIMIT 1");$q->execute(['u'=>$_SESSION['usuario_id']??0,'a'=>$id]);$curso=$q->fetch();if(!$curso){http_response_code(403);exit('No tienes acceso a este curso.');}$portal=portalEstudianteCabecera($curso['nombre'],'cursos','Contenido y evaluaciones autorizadas para tu matrícula.');$q=$pdo->prepare("SELECT id,titulo,descripcion,created_at FROM contenidos WHERE asignatura_id=:a AND docente_id=:d AND estado='activo' ORDER BY created_at DESC");$q->execute(['a'=>$id,'d'=>$curso['docente_id']]);$contenidos=$q->fetchAll();$q=$pdo->prepare("SELECT id,titulo,descripcion,fecha_apertura,fecha_cierre,nota_maxima FROM evaluaciones WHERE asignatura_id=:a AND docente_id=:d AND estado='publicada' AND (fecha_apertura IS NULL OR fecha_apertura<=NOW()) ORDER BY fecha_cierre");$q->execute(['a'=>$id,'d'=>$curso['docente_id']]);$evaluaciones=$q->fetchAll();?>
<div class="row"><div class="col-lg-7"><div class="card"><div class="card-body"><span class="badge bg-primary"><?=atenea_e($curso['codigo'])?></span><h2 class="h4 mt-3">Contenidos</h2><?php foreach($contenidos as$c):?><div class="border-bottom py-3"><strong><?=atenea_e($c['titulo'])?></strong><p class="text-muted mb-0"><?=atenea_e((string)$c['descripcion'])?></p></div><?php endforeach;?><?php if(!$contenidos):?><p class="text-muted">No hay contenidos activos.</p><?php endif;?></div></div></div><div class="col-lg-5"><div class="card"><div class="card-body"><h2 class="h4">Evaluaciones</h2><?php foreach($evaluaciones as$e):?><div class="border-bottom py-3"><strong><?=atenea_e($e['titulo'])?></strong><small class="d-block">Cierre: <?=atenea_e($e['fecha_cierre']?date('d/m/Y H:i',strtotime($e['fecha_cierre'])):'Sin fecha')?></small></div><?php endforeach;?><?php if(!$evaluaciones):?><p class="text-muted">No hay evaluaciones publicadas.</p><?php endif;?></div></div></div></div><?php portalEstudiantePie();
